const axios = require('axios');
const token = params.token || process.env.GITHUB_TOKEN || '';
const owner = params.owner;
const repo = params.repo;
const action = params.action || 'repo';
const headers = token ? { Authorization: `token ${token}` } : {};
if (action === 'repo') {
  const resp = await axios.get(`https://api.github.com/repos/${owner}/${repo}`, { headers });
  return { name: resp.data.name, stars: resp.data.stargazers_count, forks: resp.data.forks_count, open_issues: resp.data.open_issues_count, description: resp.data.description };
} else if (action === 'issues') {
  const resp = await axios.get(`https://api.github.com/repos/${owner}/${repo}/issues?state=open&per_page=10`, { headers });
  return { issues: resp.data.map(i => ({ number: i.number, title: i.title, state: i.state, url: i.html_url })) };
} else if (action === 'prs') {
  const resp = await axios.get(`https://api.github.com/repos/${owner}/${repo}/pulls?state=open&per_page=10`, { headers });
  return { prs: resp.data.map(p => ({ number: p.number, title: p.title, author: p.user.login, url: p.html_url })) };
} else {
  throw new Error('Unknown action: ' + action);
}
